  ('pukao-d0d1b9a2-moex-00206', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '應收帳款積極式函證之回函，其中有數份表示已於期後1週內付訖，會計師應採取下列何項行動？', '["查核期後1週內應收帳款紀錄之所有變動情況", "確認那些客戶所取得之現金折扣金額是否正確", "針對期後1週內付款的客戶再度函證", "追查其收款紀錄及相關憑證，以判斷該等帳款已確定收現"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "6a0db34df973", "answer_pdf_sha1": "702ed3418265", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00207', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '關於查核人員與內部稽核人員討論內部稽核工作規劃，以協調各自作業之基礎事項，不包括下列 何者？', '["工作之時點、工作之性質、工作之範圍", "財務報表整體重大性及執行重大性", "預計選取項目之方法及樣本量", "對所執行工作作成書面紀錄，並複核查核意見"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "6a0db34df973", "answer_pdf_sha1": "702ed3418265", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00208', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '下列關於審計機關是否可以向有關公私團體或個人查詢，或調閱簿籍、憑證的敘述，何者正確？', '["審計機關為行使職權，得派員持審計部稽察證，向有關公私團體或個人查詢，或調閱簿籍、憑證", "審計機關所行使之職權，其審計對象僅限政府部門，故其不得向有關公私團體或個人查詢，或 調閱簿籍、憑證", "審計機關在報經監察院同意之前提下，得派員持稽察證向有關公私團體或個人查詢，或調閱簿 籍、憑證", "審計機關在徵得各地方檢察署或法務部調查局之同意下，得向有關公私團體或個人查詢，或調 閱簿籍、憑證"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "6a0db34df973", "answer_pdf_sha1": "702ed3418265", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00209', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '下列係海洋委員會於網站公開之108年度內部控制聲明書，如以整體內部控制之有效程度觀察， 該聲明書屬何種類型？', '["有效", "少部分無效", "部分有效", "少部分有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "6a0db34df973", "answer_pdf_sha1": "702ed3418265", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00210', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'essay', '台北公司生產馬克杯，每一單位製成品設立直接材料與直接人工標準為：
直接材料：10 磅，每磅$4.50
直接人工：1小時，每小時$15
2022 年 3月計畫生產製成品 10,000 單位；而實際生產 9,700單位，實際
結果為：
直接材料：耗用 99,000 磅
直接人工：9,600 小時，直接人工成本為$148,800
假設無期初直接材料或製成品存貨。
本月直接材料購入 100,000 磅，總成本$465,000。投入價格差異在進
貨時分離，投入效率差異在耗用材料時分離。
試作：
計算2022年3月直接材料與直接人工之價格與效率差異。（16分）
編製第小題的差異之日記簿分錄。（9 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00211', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'essay', '新竹公司購買一部機器人，成本為$200,000，估計未來 10年每年可節省
現金營業成本$50,000。新竹公司之必要報酬率為 12%。假設：現金流量
及原始投資成本皆於期末時發生，該機器人預計無最終處分價值，且所
得稅率為零。
請計算及說明：（每小題 5 分，共25 分）
淨現值（註：12%，10期的 1元年金現值為 5.65）。
回收期間。
以原始淨投資額為基礎之應計會計報酬率。
以原始平均投資額為基礎之應計會計報酬率。
假設所得稅率大於零，請說明至小題的計算結果之變化（即說明
增加、減少或不變）。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00212', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '乙公司按照營業額的10%支付業務員佣金，上一季營業額為$210,000、銷售費用為$56,000，銷售 費用包括業務員固定薪資及佣金，若這一季營業額為$168,000，則銷售費用為何？', '["$16,800", "$35,000", "$44,000", "$51,800"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00213', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '乙公司從事電子零件加工，每年進貨量為1,000,000單位，每單位$30，進貨零件之不良率為1%， 每年花費$400,000 對進貨零件進行檢查，其中包含$150,000 之工廠租金分攤與$250,000 之人工成 本。經過檢查後可確保不良零件不會進入生產線加工。現今有廠商可提供外包品質檢驗服務，並可 確保進貨零件無不良品，若乙公司採此方案將可省去花費於進貨零件檢查之人工成本，但檢驗場地 將閒置，乙公司最高可出價多少向廠商購買外包品質檢驗服務？', '["$400,000", "$450,000", "$550,000", "$700,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL)
